// inferred-not-tested:走纯函数 renderToSvg,主题样式内联进返回的 SVG(<style> in svg),不实例化 new ZenUml()(那条 React+html-to-image+head 注样式路径)
import { renderToSvg } from 'https://cdn.jsdelivr.net/npm/@zenuml/core@4/+esm';
const el = document.getElementById('zenuml'); el.style.cssText = 'height:400px;overflow:auto';
const { svg } = renderToSvg(data.code, { theme: data.theme ?? 'theme-default' });
el.innerHTML = svg;
const s = el.querySelector('svg'); if (s) s.style.maxWidth = 'none';

