import { renderToSvg } from 'https://cdn.jsdelivr.net/npm/@zenuml/core@4/+esm';
const el = document.createElement('div'); el.style.cssText = 'height:400px;overflow:auto'; shadowRoot.appendChild(el);
const { svg } = renderToSvg(data.code, { theme: data.theme ?? 'theme-default' });
el.innerHTML = svg;
